To develop a Checkers game in Python, we'll need to create several classes and methods to manage the board state, player turns, and game rules. Let's start by listing the required classes and methods.

1. **Board Class**: Manages the game board.
2. **Piece Class**: Represents individual pieces (Checkers or Kings).
3. **Game Class**: Orchestrates the game logic, player turns, and checks for win conditions.
4. **Move Class**: Represents a move on the board.

Let's start by implementing these classes and methods step-by-step.

### Step 1: Create the `Piece` class

```python
class Piece:
    def __init__(self, color):
        self.color = color
        self.is_king = False

    def make_king(self):
        self.is_king = True

    def __repr__(self):
        if self.color == 'black':
            return 'B' if not self.is_king else 'BK'
        else:
            return 'R' if not self.is_king else 'RK'
```

### Step 2: Create the `Board` class

```python
class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        for i in range(3):
            for j in range(8):
                if (i + j) % 2 == 1:
                    self.board[i][j] = Piece('black')

        for i in range(5, 8):
            for j in range(8):
                if (i + j) % 2 == 1:
                    self.board[i][j] = Piece('red')

    def display(self):
        for row in self.board:
            print(" ".join(str(piece) if piece else "." for piece in row))

    def get_piece(self, x, y):
        return self.board[x][y]

    def move_piece(self, from_pos, to_pos):
        x1, y1 = from_pos
        x2, y2 = to_pos

        piece = self.get_piece(x1, y1)
        if piece:
            self.board[x1][y1] = None
            self.board[x2][y2] = piece
            if (x2 == 0 and piece.color == 'black') or (x2 == 7 and piece.color == 'red'):
                piece.make_king()
```

### Step 3: Create the `Move` class

```python
class Move:
    def __init__(self, from_pos, to_pos):
        self.from_pos = from_pos
        self.to_pos = to_pos

    def __repr__(self):
        return f"{chr(self.from_pos[1] + ord('a'))}{8 - self.from_pos[0]}-{chr(self.to_pos[1] + ord('a'))}{8 - self.to_pos[0]}"
```

### Step 4: Create the `Game` class

```python
class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'black'
        self.history = []

    def display_board(self):
        self.board.display()

    def is_valid_move(self, move):
        x1, y1 = move.from_pos
        x2, y2 = move.to_pos

        piece = self.board.get_piece(x1, y1)
        if not piece or piece.color != self.current_player:
            return False

        dx, dy = abs(x2 - x1), abs(y2 - y1)

        if dx == 0 or dy == 0:
            return False

        if dx > 2 or dy > 2:
            return False

        if (dx + dy) % 2 != 1:
            return False

        if self.board.get_piece(x2, y2):
            return False

        # Check for jumps
        if dx == 2 and dy == 2:
            mid_x, mid_y = (x1 + x2) // 2, (y1 + y2) // 2
            jumped_piece = self.board.get_piece(mid_x, mid_y)
            if not jumped_piece or jumped_piece.color != self.current_player:
                return False

        return True

    def make_move(self, move):
        if not self.is_valid_move(move):
            raise ValueError("Invalid move")

        x1, y1 = move.from_pos
        x2, y2 = move.to_pos

        piece = self.board.get_piece(x1, y1)
        self.board.move_piece((x1, y1), (x2, y2))

        # Handle jumps
        dx, dy = abs(x2 - x1), abs(y2 - y1)
        if dx == 2 and dy == 2:
            mid_x, mid_y = (x1 + x2) // 2, (y1 + y2) // 2
            jumped_piece = self.board.get_piece(mid_x, mid_y)
            self.board.move_piece((mid_x, mid_y), None)

        self.history.append(move)
        self.current_player = 'red' if self.current_player == 'black' else 'black'

    def check_winner(self):
        black_pieces = sum(1 for row in self.board.board for piece in row if piece and piece.color == 'black')
        red_pieces = sum(1 for row in self.board.board for piece in row if piece and piece.color == 'red')

        if black_pieces == 0:
            return 'Red wins'
        elif red_pieces == 0:
            return 'Black wins'

        return None

    def prompt_move(self):
        move_str = input(f"{self.current_player}'s turn (e.g., a1-c3): ").strip().lower()
        try:
            from_pos = (int(move_str[1]) - 1, ord(move_str[0]) - ord('a'))
            to_pos = (int(move_str[4]) - 1, ord(move_str[3]) - ord('a'))
            move = Move(from_pos, to_pos)
        except Exception as e:
            print(f"Invalid input: {e}")
            return None

        return move
```

### Step 5: Main Game Loop

```python
def main():
    game = Game()
    winner = None

    while not winner:
        game.display_board()
        move = game.prompt_move()

        if move:
            try:
                game.make_move(move)
            except ValueError as e:
                print(e)
                continue

            winner = game.check_winner()

    game.display_board()
    print(winner)

if __name__ == "__main__":
    main()
```

